import { CONFIG, QueryKeys } from "@/modules/core";
import { InfiniteData, infiniteQueryOptions, queryOptions } from "@tanstack/react-query";
import { Entry } from "../types";
import { filterDmcaEntry } from "../utils/filter-dmca-entries";
import { getPostsRanked } from "@/modules/bridge";
import { callRPC } from "@/modules/core/hive-tx";

type PageParam = {
  author: string | undefined;
  permlink: string | undefined;
  hasNextPage: boolean;
};

interface GetPostsRankedOptions {
  resolvePosts?: boolean;
}

export function getPostsRankedInfiniteQueryOptions(
  sort: string,
  tag: string,
  limit = 20,
  observer = "",
  enabled = true,
  _options: GetPostsRankedOptions = {}
) {
  return infiniteQueryOptions<
    Entry[],
    Error,
    InfiniteData<Entry[], PageParam>,
    (string | number)[],
    PageParam
  >({
    queryKey: QueryKeys.posts.postsRanked(sort, tag, limit, observer),
    queryFn: async ({ pageParam, signal }: { pageParam: PageParam; signal: AbortSignal }) => {
      if (!pageParam.hasNextPage) {
        return [];
      }

      let sanitizedTag = tag;
      if (CONFIG.dmcaTagRegexes.some((regex) => regex.test(tag))) {
        sanitizedTag = "";
      }

      const response = await callRPC("bridge.get_ranked_posts", {
        sort,
        start_author: pageParam.author,
        start_permlink: pageParam.permlink,
        limit,
        tag: sanitizedTag,
        observer,
      }, undefined, undefined, signal);

      if (response === null || response === undefined) {
        return [];
      }

      if (!Array.isArray(response)) {
        throw new Error(
          `[SDK] get_ranked_posts returned ${typeof response} for sort=${sort}`
        );
      }

      const data = response as Entry[];

      // Capture pinned entries BEFORE the in-place created-date sort: the
      // bridge surfaces them at the head of the response in the community
      // moderators' chosen order, which the sort would scatter by age.
      // Keep EVERY pin — the previous post-sort find() kept a single pin and
      // silently dropped the rest, so multi-pin communities never displayed
      // their other pinned posts on any page. Pins only occur on the first
      // page (cursor pages return none), so this is a no-op elsewhere.
      const pinnedEntries = data.filter((s) => s.stats?.is_pinned);

      // Sort by created date unless it's "hot"
      const sorted =
        sort === "hot"
          ? data
          : data.sort(
              (a, b) =>
                new Date(b.created).getTime() - new Date(a.created).getTime()
            );

      const nonPinnedEntries = sorted.filter((s) => !s.stats?.is_pinned);

      const combined = [...pinnedEntries, ...nonPinnedEntries];
      return filterDmcaEntry(combined);
    },
    enabled,
    initialPageParam: {
      author: undefined,
      permlink: undefined,
      hasNextPage: true,
    } as PageParam,
    getNextPageParam: (lastPage: Entry[]) => {
      const last = lastPage?.[lastPage.length - 1];
      return {
        author: last?.author,
        permlink: last?.permlink,
        hasNextPage: (lastPage?.length ?? 0) > 0,
      };
    },
  });
}

export function getPostsRankedQueryOptions(
  sort: string,
  start_author: string = "",
  start_permlink: string = "",
  limit: number = 20,
  tag: string = "",
  observer: string = "",
  enabled = true
) {
  return queryOptions({
    queryKey: QueryKeys.posts.postsRankedPage(sort, start_author, start_permlink, limit, tag, observer),
    enabled,
    queryFn: async ({ signal } = {} as any) => {
      let sanitizedTag = tag;
      if (CONFIG.dmcaTagRegexes.some((regex) => regex.test(tag))) {
        sanitizedTag = "";
      }

      const response = await getPostsRanked(
        sort,
        start_author,
        start_permlink,
        limit,
        sanitizedTag,
        observer,
        signal
      );

      return filterDmcaEntry(response ?? []) as Entry[];
    },
  });
}
